package test.rice.obj;

import main.rice.obj.*;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Test cases for the PyListObj class.
 */
class PyListObjTest {

    // Empty list
    private static final PyListObj<PyIntObj> emptyList =
        new PyListObj<>(new ArrayList<>());

    // Another empty list (distinct object)
    private static final PyListObj<PyIntObj> emptyList2 =
        new PyListObj<>(new ArrayList<>());

    // Simple list with single element
    private static final PyListObj<PyIntObj> singleList =
        new PyListObj<>(Arrays.asList(new PyIntObj(1)));

    // Simple list with multiple elements
    private static final PyListObj<PyIntObj> multiList =
        new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2), new PyIntObj(3)));

    // Another multiList with same values (distinct object)
    private static final PyListObj<PyIntObj> multiList2 =
        new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2), new PyIntObj(3)));

    // Nested list: [[1, 2], [3, 4]]
    private static final PyListObj<PyListObj<PyIntObj>> nestedList =
        new PyListObj<>(Arrays.asList(
            new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2))),
            new PyListObj<>(Arrays.asList(new PyIntObj(3), new PyIntObj(4)))
        ));

    // Another nested list with same values
    private static final PyListObj<PyListObj<PyIntObj>> nestedList2 =
        new PyListObj<>(Arrays.asList(
            new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2))),
            new PyListObj<>(Arrays.asList(new PyIntObj(3), new PyIntObj(4)))
        ));

    // Subset list [1, 2]
    private static final PyListObj<PyIntObj> subsetList =
        new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2)));

    @Test
    void testGetValueNested() {
        List<PyListObj<PyIntObj>> value = nestedList.getValue();
        assertEquals(2, value.size());
        assertEquals(2, value.get(0).getValue().size());
    }

    @Test
    void testToStringEmpty() {
        assertEquals("[]", emptyList.toString());
    }

    @Test
    void testToStringSimpleSingle() {
        assertEquals("[1]", singleList.toString());
    }

    @Test
    void testToStringSimpleMultiple() {
        assertEquals("[1, 2, 3]", multiList.toString());
    }

    @Test
    void testToStringNestedEmpty() {
        PyListObj<PyListObj<PyIntObj>> nestedEmpty =
            new PyListObj<>(Arrays.asList(new PyListObj<>(new ArrayList<>())));
        assertEquals("[[]]", nestedEmpty.toString());
    }

    @Test
    void testToStringNestedMultiple() {
        assertEquals("[[1, 2], [3, 4]]", nestedList.toString());
    }

    @Test
    void testEqualsEmptyDifferent() {
        assertEquals(emptyList, emptyList2);
    }

    @Test
    void testEqualsSimple() {
        assertEquals(multiList, multiList2);
    }

    @Test
    void testNotEqual() {
        assertNotEquals(singleList, multiList);
    }

    @Test
    void testNotEqualSubset1() {
        assertNotEquals(multiList, subsetList);
    }

    @Test
    void testNotEqualSubset2() {
        assertNotEquals(subsetList, multiList);
    }

    @Test
    void testNotEqualNonAPyObj() {
        assertNotEquals(multiList, Arrays.asList(1, 2, 3));
    }

    @Test
    void testHashCodeNotEqual() {
        assertNotEquals(singleList.hashCode(), multiList.hashCode());
    }

    @Test
    void testEqualsNested() {
        assertEquals(nestedList, nestedList2);
    }

    @Test
    void testHashCodeEqual() {
        assertEquals(multiList.hashCode(), multiList2.hashCode());
    }
}

package test.rice.obj;

import main.rice.obj.*;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Test cases for the PyDictObj class.
 */
class PyDictObjTest {

    // Empty dict
    private static final PyDictObj<PyIntObj, PyIntObj> emptyDict =
        new PyDictObj<>(new LinkedHashMap<>());

    // Another empty dict (distinct object)
    private static final PyDictObj<PyIntObj, PyIntObj> emptyDict2 =
        new PyDictObj<>(new LinkedHashMap<>());

    // Single entry dict
    private static final PyDictObj<PyIntObj, PyStringObj> singleDict;

    // Multiple entry dict - use LinkedHashMap for predictable order
    private static final PyDictObj<PyIntObj, PyStringObj> multiDict;
    private static final PyDictObj<PyIntObj, PyStringObj> multiDict2;

    // Nested dict
    private static final PyDictObj<PyIntObj, PyDictObj<PyIntObj, PyIntObj>> nestedDict;
    private static final PyDictObj<PyIntObj, PyDictObj<PyIntObj, PyIntObj>> nestedDict2;

    // Subset dict
    private static final PyDictObj<PyIntObj, PyStringObj> subsetDict;

    static {
        // Single dict: {1: 'a'}
        Map<PyIntObj, PyStringObj> s1 = new LinkedHashMap<>();
        s1.put(new PyIntObj(1), new PyStringObj("a"));
        singleDict = new PyDictObj<>(s1);

        // Multi dict: {1: 'a', 2: 'b'}
        Map<PyIntObj, PyStringObj> m1 = new LinkedHashMap<>();
        m1.put(new PyIntObj(1), new PyStringObj("a"));
        m1.put(new PyIntObj(2), new PyStringObj("b"));
        multiDict = new PyDictObj<>(m1);

        Map<PyIntObj, PyStringObj> m2 = new LinkedHashMap<>();
        m2.put(new PyIntObj(1), new PyStringObj("a"));
        m2.put(new PyIntObj(2), new PyStringObj("b"));
        multiDict2 = new PyDictObj<>(m2);

        // Subset dict: {1: 'a'}
        Map<PyIntObj, PyStringObj> sub = new LinkedHashMap<>();
        sub.put(new PyIntObj(1), new PyStringObj("a"));
        subsetDict = new PyDictObj<>(sub);

        // Nested dict: {1: {2: 3}}
        Map<PyIntObj, PyIntObj> inner = new LinkedHashMap<>();
        inner.put(new PyIntObj(2), new PyIntObj(3));
        Map<PyIntObj, PyDictObj<PyIntObj, PyIntObj>> n1 = new LinkedHashMap<>();
        n1.put(new PyIntObj(1), new PyDictObj<>(inner));
        nestedDict = new PyDictObj<>(n1);

        Map<PyIntObj, PyIntObj> inner2 = new LinkedHashMap<>();
        inner2.put(new PyIntObj(2), new PyIntObj(3));
        Map<PyIntObj, PyDictObj<PyIntObj, PyIntObj>> n2 = new LinkedHashMap<>();
        n2.put(new PyIntObj(1), new PyDictObj<>(inner2));
        nestedDict2 = new PyDictObj<>(n2);
    }

    @Test
    void testGetValueNested() {
        Map<PyIntObj, PyDictObj<PyIntObj, PyIntObj>> value = nestedDict.getValue();
        assertEquals(1, value.size());
    }

    @Test
    void testToStringEmpty() {
        assertEquals("{}", emptyDict.toString());
    }

    @Test
    void testToStringSingle() {
        assertEquals("{1: 'a'}", singleDict.toString());
    }

    @Test
    void testToStringMultiple() {
        assertEquals("{1: 'a', 2: 'b'}", multiDict.toString());
    }

    @Test
    void testToStringNested() {
        assertEquals("{1: {2: 3}}", nestedDict.toString());
    }

    @Test
    void testEqualsEmpty() {
        assertEquals(emptyDict, emptyDict2);
    }

    @Test
    void testEqualsNonEmpty() {
        assertEquals(multiDict, multiDict2);
    }

    @Test
    void testNotEqual() {
        assertNotEquals(singleDict, multiDict);
    }

    @Test
    void testNotEqualSubset1() {
        assertNotEquals(multiDict, subsetDict);
    }

    @Test
    void testNotEqualSubset2() {
        assertNotEquals(subsetDict, multiDict);
    }

    @Test
    void testNotEqualNonAPyObj() {
        Map<Integer, String> rawMap = new HashMap<>();
        rawMap.put(1, "a");
        assertNotEquals(singleDict, rawMap);
    }

    @Test
    void testEqualsNested() {
        assertEquals(nestedDict, nestedDict2);
    }

    @Test
    void testHashCodeEqual() {
        assertEquals(multiDict.hashCode(), multiDict2.hashCode());
    }

    @Test
    void testHashCodeNotEqual() {
        assertNotEquals(singleDict.hashCode(), multiDict.hashCode());
    }
}

package test.rice.obj;

import main.rice.obj.*;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Test cases for the PySetObj class.
 */
class PySetObjTest {

    // Empty set
    private static final PySetObj<PyIntObj> emptySet =
        new PySetObj<>(new HashSet<>());

    // Another empty set (distinct object)
    private static final PySetObj<PyIntObj> emptySet2 =
        new PySetObj<>(new HashSet<>());

    // Single element set
    private static final PySetObj<PyIntObj> singleSet =
        new PySetObj<>(new HashSet<>(Arrays.asList(new PyIntObj(1))));

    // Multiple element set - use LinkedHashSet for predictable order
    private static final PySetObj<PyIntObj> multiSet;
    private static final PySetObj<PyIntObj> multiSet2;

    static {
        Set<PyIntObj> s1 = new LinkedHashSet<>();
        s1.add(new PyIntObj(1));
        s1.add(new PyIntObj(2));
        s1.add(new PyIntObj(3));
        multiSet = new PySetObj<>(s1);

        Set<PyIntObj> s2 = new LinkedHashSet<>();
        s2.add(new PyIntObj(1));
        s2.add(new PyIntObj(2));
        s2.add(new PyIntObj(3));
        multiSet2 = new PySetObj<>(s2);
    }

    // Subset
    private static final PySetObj<PyIntObj> subsetSet =
        new PySetObj<>(new HashSet<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2))));

    @Test
    void testGetValue() {
        Set<PyIntObj> value = multiSet.getValue();
        assertEquals(3, value.size());
    }

    @Test
    void testToStringEmpty() {
        // Python's empty set is set(), not {} (which is an empty dict)
        assertEquals("set()", emptySet.toString());
    }

    @Test
    void testToStringSingle() {
        assertEquals("{1}", singleSet.toString());
    }

    @Test
    void testToStringMultiple() {
        // Set order may vary, so check it contains correct format
        String str = multiSet.toString();
        assertTrue(str.startsWith("{"));
        assertTrue(str.endsWith("}"));
        assertTrue(str.contains("1"));
        assertTrue(str.contains("2"));
        assertTrue(str.contains("3"));
    }

    @Test
    void testEqualsEmpty() {
        assertEquals(emptySet, emptySet2);
    }

    @Test
    void testEqualsMultiple() {
        assertEquals(multiSet, multiSet2);
    }

    @Test
    void testNotEqual() {
        assertNotEquals(singleSet, multiSet);
    }

    @Test
    void testNotEqualSubset1() {
        assertNotEquals(multiSet, subsetSet);
    }

    @Test
    void testNotEqualSubset2() {
        assertNotEquals(subsetSet, multiSet);
    }

    @Test
    void testNotEqualNonAPyObj() {
        assertNotEquals(multiSet, new HashSet<>(Arrays.asList(1, 2, 3)));
    }

    @Test
    void testHashCodeEqual() {
        assertEquals(multiSet.hashCode(), multiSet2.hashCode());
    }

    @Test
    void testHashCodeNotEqual() {
        assertNotEquals(singleSet.hashCode(), multiSet.hashCode());
    }
}

