    private static final PyTupleObj<PyIntObj> multiTuple2 =
        new PyTupleObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2), new PyIntObj(3)));

    // Nested tuple: ((1, 2), (3, 4))
