        assertNotEquals(multiTuple, subsetTuple);
    }

    @Test
    void testNotEqualSubset2() {
        assertNotEquals(subsetTuple, multiTuple);
    }

    @Test
    void testNotEqualNonAPyObj() {
        assertNotEquals(multiTuple, Arrays.asList(1, 2, 3));
    }

    @Test
    void testEqualsNested() {
